import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from './api';
import logo from './assets/logo.png';

function Login() {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleLogin = async (event) => {
    event.preventDefault();
    setError('');
    setLoading(true);

    try {
      const res = await api.post('/login', {
        email,
        username: email,
        password
      });

      if (res.data.token || res.data.success) {
        localStorage.setItem('token', res.data.token || '');
        localStorage.setItem('user', JSON.stringify(res.data.user || { email, role: 'operator' }));
        navigate('/home');
        return;
      }

      setError('Login inválido');
    } catch (err) {
      const message = err.response?.data?.message || err.response?.data?.error || 'Erro ao fazer login';
      setError(message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <main className="login-page">
      <section className="login-brand">
        <img src={logo} alt="GRC Consultoria Empresarial" className="login-brand-logo" />
        <p className="eyebrow">Gestão de experiência do paciente</p>
        <h1>Reclamações tratadas com método, prazo e visibilidade.</h1>
        <p>
          Centralize registros, acompanhe tratativas e transforme os principais motivos
          de reclamação em indicadores para a operação.
        </p>

        <div className="login-highlights">
          <span>Clínicas</span>
          <span>Operação</span>
          <span>BI</span>
        </div>
      </section>

      <section className="login-panel" aria-label="Acesso ao sistema">
        <form className="login-card" onSubmit={handleLogin}>
          <img src={logo} alt="GRC Consultoria Empresarial" className="form-logo" />
          <h2>Acessar sistema</h2>
          <p>Entre para registrar, acompanhar e encerrar reclamações.</p>

        <input
          className="field"
          type="email"
          placeholder="Email"
          value={email}
          onChange={(event) => setEmail(event.target.value)}
          autoComplete="email"
          required
        />

        <input
          className="field"
          type="password"
          placeholder="Senha"
          value={password}
          onChange={(event) => setPassword(event.target.value)}
          autoComplete="current-password"
          required
        />

        {error && <p className="form-error">{error}</p>}

        <button className="primary-action" type="submit" disabled={loading}>
          {loading ? 'Entrando...' : 'Entrar'}
        </button>

          <small className="login-help">
            Acesso inicial: admin@sorria.com / 123456
          </small>
      </form>
      </section>
    </main>
  );
}

export default Login;
